const raw = $('Supabase Fetch').item.json.master_profile;
const p = typeof raw === 'string' ? JSON.parse(raw) : raw;
const rawOutput = $input.item.json.output || '';

function esc(str) {
  if (!str) return '';
  return String(str)
    .replace(/\\/g, '\\textbackslash{}')
    .replace(/([&%$#{}])/g, '\\$1')
    .replace(/~/g, '\\textasciitilde{}')
    .replace(/\^/g, '\\textasciicircum{}')
    .replace(/_/g, '\\_');
}

const c = p.contact || {};

let cl = {};
try {
  const cleaned = rawOutput.replace(/\`\`\`json|\`\`\`/gi, '').trim();
  const parsed = JSON.parse(cleaned);
  cl = parsed.cover_letter || parsed;
} catch (e) {
  console.warn('Failed to parse cover letter JSON output, falling back to plain text parsing:', e);
  cl = {
    subject_role: p.tagline || 'Software Developer',
    recipient: 'Hiring Manager',
    paragraph_1: rawOutput || 'I am excited to apply for this position.',
    paragraph_2: '',
    bullet_points: [],
    paragraph_3: ''
  };
}

let bulletsTex = '';
if (cl.bullet_points && Array.isArray(cl.bullet_points)) {
  cl.bullet_points.forEach(b => {
    if (b && (b.title || b.detail)) {
      bulletsTex += `    \\item \\textbf{${esc(b.title || '')}:} ${esc(b.detail || '')}\n`;
    }
  });
}

